return [{ json: {
  research_goal: 'Understand why mid-market project managers switch from incumbent tools to ours, and what barriers prevent full adoption after signing',
  interview_type: 'discovery',
  participant_profile: 'Mid-market (50-500 employees) project manager, using our product for 3-6 months, came from Asana or Monday.com',
  topic_areas: ['switching motivation', 'onboarding experience', 'daily workflow fit', 'collaboration with non-PM stakeholders', 'blockers to full team adoption', 'unmet needs'],
  duration_minutes: 45,
  format: 'semi-structured',
  researcher_note: 'We want to understand adoption gaps. Avoid leading questions about features.'
} }];

const d = $input.first().json;
const topicText = d.topic_areas.map((t, i) => `  ${i+1}. ${t}`).join('\n');
const system = `You are an expert UX researcher and interviewer. You write clear, unbiased, open-ended interview guides. You avoid leading questions. You include probes for each major question. Return ONLY valid JSON.`;
const user = `Create a ${d.duration_minutes}-minute ${d.format} ${d.interview_type} interview guide.

Research goal: ${d.research_goal}
Participant profile: ${d.participant_profile}
Researcher note: ${d.researcher_note || 'none'}

Topic areas to cover:
${topicText}

Return JSON:
{
  "interview_title": "string",
  "estimated_duration_minutes": ${d.duration_minutes},
  "research_goal": "string",
  "screener_questions": ["string — 2-3 screener questions to validate participant fits profile"],
  "warm_up_questions": ["string — 2 easy opening questions"],
  "sections": [
    {
      "section_title": "string",
      "section_goal": "string",
      "estimated_time_minutes": 8,
      "questions": [
        { "question": "string", "type": "open|probe|hypothetical", "probes": ["string — follow-up probe questions"] }
      ]
    }
  ],
  "closing_questions": ["string — 2-3 wrap-up questions"],
  "do_not_ask": ["string — topics or question patterns to avoid based on researcher note"],
  "analysis_framework": "string — how to organize and analyze the interview data"
}`;
return [{ json: { data: d, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Interview Guide Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.sections || !Array.isArray(parsed.sections)) return [{ json: { _error: true, reason: 'Missing sections' } }];
return [{ json: { _error: false, guide: parsed, meta: { research_goal: upstream.data.research_goal, participant_profile: upstream.data.participant_profile, generated_at: new Date().toISOString() } } }];
